import React from "react";
import { Route } from "@/types/route";
import { Link } from "react-router-dom";

const routeCardStyle: React.CSSProperties = {
  background: "white",
  borderRadius: "12px",
  padding: "18px",
  textDecoration: "none",
  color: "inherit",
  display: "flex",
  justifyContent: "space-between",
  borderLeft: "6px solid #003057",
  boxShadow: "0 2px 8px rgba(0,0,0,0.08)",
  transition: "0.2s ease",
};

const routeCardHoverStyle: React.CSSProperties = {
  transform: "translateY(-4px)",
  boxShadow: "0 8px 20px rgba(0,0,0,0.12)",
};

const goldBorderStyle: React.CSSProperties = {
  borderLeftColor: "#B3A369",
};

const defaultBorderStyle: React.CSSProperties = {
  borderLeftColor: "#003057",
};

const routeHeaderStyle: React.CSSProperties = {
  display: "flex",
  alignItems: "center",
  gap: "12px",
};

const routeNameStyle: React.CSSProperties = {
  fontSize: "20px",
  fontWeight: 700,
  color: "#003057",
};

const routeBadgeStyle: React.CSSProperties = {
  padding: "4px 10px",
  borderRadius: "12px",
  fontSize: "11px",
  fontWeight: 600,
  backgroundColor: "#d4edda",
  color: "#155724",
};

const routeDetailsStyle: React.CSSProperties = {
  display: "flex",
  gap: "16px",
  marginTop: "8px",
  fontSize: "13px",
  color: "#666",
};

const detailItemStyle: React.CSSProperties = {
  display: "flex",
  alignItems: "center",
  gap: "6px",
};

const routeArrowStyle: React.CSSProperties = {
  fontSize: "22px",
  color: "#ccc",
};

const delayIndicatorStyle: React.CSSProperties = {
  background: "#fff3cd",
  padding: "3px 8px",
  borderRadius: "6px",
  fontSize: "12px",
  color: "#856404",
};

interface Props {
  route: Route;
}

const RouteCard: React.FC<Props> = ({ route }) => {
  const colorStyle = route.color?.toLowerCase().includes("b3a369")
    ? goldBorderStyle
    : defaultBorderStyle;

  return (
    <Link
      to={`/bus-routes?routeId=${route.id}`}
      style={{ ...routeCardStyle, ...colorStyle }}
    >
      <div style={routeCardStyle}>
        <div style={routeHeaderStyle}>
          <div style={routeNameStyle}>{route.name}</div>
          <span style={routeBadgeStyle}>Active</span>
        </div>
        <div style={routeDetailsStyle}>
          <div style={detailItemStyle}>📍 {route.stops.length} Stops</div>
          <div style={detailItemStyle}>
            🚌 {route.busLocations?.length ?? 0} Buses
          </div>
          <div style={detailItemStyle}>
            <span style={delayIndicatorStyle}>+2 min</span>
          </div>
        </div>
      </div>

      <div style={routeArrowStyle}>→</div>
    </Link>
  );
};

export default RouteCard;
